class SmallestInfiniteSet {
    private pq: typeof MinPriorityQueue;
    private s: Set<number>;

    constructor() {
        this.pq = new MinPriorityQueue();
        this.s = new Set();
        for (let i = 1; i <= 1000; i++) {
            this.pq.enqueue(i, i);
            this.s.add(i);
        }
    }

    popSmallest(): number {
        const x = this.pq.dequeue()?.element;
        this.s.delete(x);
        return x;
